if ( form.getField("operation").getValue() != null && operation.equalsIgnoreCase("Remove Access") ) {
form.getField("all").setHidden(false);
}

import java.util.ArrayList;
import sailpoint.api.*;
import sailpoint.object.*;

List ents = new ArrayList();

for ( int i=1; i<=100 ; i++ )  {

ents.add("Entitlement" + i);
}

return ents;
//   return Arrays.asList("Ent1","Ent2","Ent3");

if ( form.getField("operation").getValue() != null ) {
  if ( all != null && all ) {
    List ents = new ArrayList();
    for ( int i=1; i<=100 ; i++ )  {
      ents.add("Entitlement" + i);
    }
    form.getField("entitlement").setValue(ents);
    //  form.getField("entitlement").setValue(Arrays.asList("Ent1","Ent2","Ent3"));
  } else if ( all != null && !all ) {
    form.getField("entitlement").setValue(null);
  }
  form.getField("entitlement").setHidden(false);
}

ValidationScript.Source:
import sailpoint.tools.Util;
import sailpoint.tools.Message;
import sailpoint.object.Identity;


log.error("identity--------- " + identity);

List messages = new ArrayList();

if ( identityName != null ) {

Identity identity = context.getObjectByName(Identity.class, identityName);

String access = identity.getAttribute("access");

if (value != null && identity != null && access != null ) {

List accessList = Util.stringToList(access);

int accessesSize = Util.nullSafeSize(accessList) + Util.nullSafeSize(value);

if( accessesSize > 50) {

Message msg = new Message();
msg.setKey("You cannot add more than 50 entitlements. Please review your current entitlements and remove any unnecessary ones.");
messages.add(msg);

}
}
}

return messages;
